```typescript
import { GoogleGenAI, Modality } from "@google/genai";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateCityIllustration = async (visualPrompt: string): Promise<string | null> => {
  if (!apiKey) {
    console.error("No API Key found");
    return null;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: visualPrompt }],
      },
      config: {
        responseModalities: [Modality.IMAGE],
      }
    });

    const part = response.candidates?.[0]?.content?.parts?.[0];
    if (part && part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) {
    console.error("Error generating illustration:", error);
    return null;
  }
};

export const transformImageToEtching = async (imageBase64: string): Promise<string | null> => {
  if (!apiKey) return null;

  // Extract the raw base64 string (remove data:image/xxx;base64, prefix)
  const base64Data = imageBase64.split(',')[1];
  const mimeType = imageBase64.split(';')[0].split(':')[1];

  const prompt = `
    Transform this image into a high-quality axonometric isometric drawing.
    Style: M.C. Escher style etching, black ink on white paper.

    STRICT VISUAL CONSTRAINT:
    The composition must be constructed EXCLUSIVELY using these architectural elements:
    1. Arches
    2. Tiles
    3. Trusses
    4. Columns
    5. Doors
    6. Windows
    7. Vaults

    Do not render organic forms, people, trees, or water. 
    Reinterpret the shapes in the uploaded image using only the architectural blocks listed above.
    Technique: Detailed cross-hatching, fine linework, architectural precision.
    White background.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Data
            }
          },
          { text: prompt }
        ],
      },
      config: {
        responseModalities: [Modality.IMAGE],
      }
    });

    const part = response.candidates?.[0]?.content?.parts?.[0];
    if (part && part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
    return null;
  } catch (error) {
    console.error("Error transforming image:", error);
    return null;
  }
};
